import uuid
from decimal import Decimal

import pytest
from sqlalchemy import create_engine
from sqlalchemy.exc import IntegrityError
from sqlalchemy.orm import sessionmaker

# SQLite has no native DECIMAL type; SQLAlchemy binds Numeric(28,10) values via float,
# so exact base-10 fractions (e.g. .1234567890) can drift at the ~15th significant digit
# on round-trip. Production (MySQL) stores DECIMAL exactly — this tolerance is a SQLite
# test-double artifact, not a real precision loss. 1e-6 is far tighter than money needs.
_MONEY_TOL = Decimal("0.000001")


def assert_money_equal(actual: Decimal, expected: Decimal) -> None:
    assert abs(actual - expected) < _MONEY_TOL, f"{actual} != {expected} (tol={_MONEY_TOL})"

