    with engine.connect() as conn:
        conn.exec_driver_sql("PRAGMA foreign_keys=ON")
    Base.metadata.create_all(engine)
    # expire_on_commit=False: SQLite Numeric binds Decimal via float (no native decimal
    # support), so a post-commit attribute refresh isn't meaningful here anyway; this also
    # keeps client-generated UUID PKs (default=uuid.uuid4) readable off already-expunged
    # objects without a DetachedInstanceError, while session.get() after expunge_all()
