def _run(session, period, status=RunStatus.COMPLETED, trigger=RunTrigger.MANUAL, trade_date="20260603"):
    r = PostTradeAllocationRun(
        trade_date=trade_date, period_id=period.id, status=status, trigger=trigger
    )
    session.add(r)
    session.commit()
