# --- DB-1: post_trade_allocation_runs ---------------------------------------


def test_run_persists_and_reloads_enum_values(session, period):
    run = _run(session, period, status=RunStatus.EMPTY, trigger=RunTrigger.SCHEDULED)
    session.expunge_all()

    reloaded = session.get(PostTradeAllocationRun, run.id)
    assert reloaded.status == RunStatus.EMPTY
    assert reloaded.trigger == RunTrigger.SCHEDULED
    assert reloaded.status.value == "empty"
    assert reloaded.trigger.value == "scheduled"


def test_run_trade_date_not_unique_two_rows_same_date_persist(session, period):
    r1 = _run(session, period, trade_date="20260603")
    r2 = _run(session, period, trade_date="20260603")
    assert r1.id != r2.id
    assert session.query(PostTradeAllocationRun).filter_by(trade_date="20260603").count() == 2


def test_run_missing_trigger_raises_on_commit(session, period):
    run = PostTradeAllocationRun(trade_date="20260603", period_id=period.id, status=RunStatus.COMPLETED)
    session.add(run)
