# --- DB-2: post_trade_allocations -------------------------------------------


def test_cell_row_persists_and_reloads_signed_values(session, period, model, user):
    run = _run(session, period)
    cell = PostTradeAllocation(
        run_id=run.id,
        model_id=model.id,
        user_id=user.id,
        model_traded=Decimal("-6800000.1234567890"),
        units=Decimal("5.0000000000"),
        units_total=Decimal("25.0000000000"),
        allocated=Decimal("-1360000.1234567890"),
        pct=Decimal("20.000"),
        ib_account="U-1234567",
        model_name="Zero",
        model_acct="U-9999999",
    )
    session.add(cell)
    session.commit()
    session.expunge_all()

    reloaded = session.get(PostTradeAllocation, (run.id, model.id, user.id))
    assert_money_equal(reloaded.model_traded, Decimal("-6800000.1234567890"))
    assert_money_equal(reloaded.allocated, Decimal("-1360000.1234567890"))


@pytest.mark.parametrize("sign", [1, -1])
def test_cell_row_sign_survives_round_trip(session, period, model, user, sign):
    run = _run(session, period)
    traded = Decimal("1234567.1234567890") * sign
    allocated = Decimal("246913.4246913578") * sign
    cell = PostTradeAllocation(
        run_id=run.id,
        model_id=model.id,
        user_id=user.id,
        model_traded=traded,
        units=Decimal("1"),
        units_total=Decimal("1"),
        allocated=allocated,
        pct=Decimal("100.000"),
        model_name="Zero",
    )
    session.add(cell)
    session.commit()
    session.expunge_all()

    reloaded = session.get(PostTradeAllocation, (run.id, model.id, user.id))
    assert (reloaded.model_traded > 0) == (traded > 0)
    assert (reloaded.allocated > 0) == (allocated > 0)
    assert_money_equal(reloaded.model_traded, traded)
    assert_money_equal(reloaded.allocated, allocated)


